if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $('Auth Guard').first().json;
const action = (body.action || 'list').toLowerCase();
const esc = s => (s || '').replace(/'/g, "''");
let query = '';
let meta = { action };

switch (action) {
  case 'upsert':
  case 'create':
    query = `INSERT INTO gda_teaming_partners (company_name, cage_code, duns, uei, size_status, socio_economic, naics_codes, core_capabilities, past_teaming_with_gda, past_teaming_details, contract_vehicles, geographic_presence, key_personnel, relationship_strength, nda_status, ta_status, notes, source, updated_at)
      VALUES ('${esc(body.company_name)}', '${esc(body.cage_code)}', '${esc(body.duns)}', '${esc(body.uei)}', '${esc(body.size_status)}', '${esc(body.socio_economic)}', '${esc(body.naics_codes)}', '${esc(body.core_capabilities)}', ${body.past_teaming_with_gda || false}, '${esc(body.past_teaming_details)}', '${esc(body.contract_vehicles)}', '${esc(body.geographic_presence)}', '${esc(body.key_personnel)}', '${esc(body.relationship_strength || 'New')}', '${esc(body.nda_status || 'None')}', '${esc(body.ta_status || 'None')}', '${esc(body.notes)}', '${esc(body.source || 'Manual')}', NOW())
      ON CONFLICT (uei) DO UPDATE SET
        company_name = EXCLUDED.company_name,
        size_status = COALESCE(NULLIF(EXCLUDED.size_status,''), gda_teaming_partners.size_status),
        naics_codes = COALESCE(NULLIF(EXCLUDED.naics_codes,''), gda_teaming_partners.naics_codes),
        core_capabilities = COALESCE(NULLIF(EXCLUDED.core_capabilities,''), gda_teaming_partners.core_capabilities),
        relationship_strength = COALESCE(NULLIF(EXCLUDED.relationship_strength,'New'), gda_teaming_partners.relationship_strength),
        nda_status = COALESCE(NULLIF(EXCLUDED.nda_status,'None'), gda_teaming_partners.nda_status),
        ta_status = COALESCE(NULLIF(EXCLUDED.ta_status,'None'), gda_teaming_partners.ta_status),
        notes = COALESCE(NULLIF(EXCLUDED.notes,''), gda_teaming_partners.notes),
        updated_at = NOW()
      RETURNING *;`;
    meta.action = 'upsert';
    break;
  case 'delete':
    query = `DELETE FROM gda_teaming_partners WHERE id = ${parseInt(body.id) || 0} RETURNING id, company_name;`;
    break;
  case 'search':
    const q = esc(body.q || '');
    query = `SELECT * FROM gda_teaming_partners WHERE company_name ILIKE '%${q}%' OR naics_codes ILIKE '%${q}%' OR core_capabilities ILIKE '%${q}%' OR socio_economic ILIKE '%${q}%' ORDER BY relationship_strength DESC, updated_at DESC LIMIT 25;`;
    break;
  case 'match':
    const naics = esc(body.naics || '');
    const setAside = esc(body.set_aside || '');
    query = `SELECT * FROM gda_teaming_partners WHERE naics_codes ILIKE '%${naics}%' ${setAside ? "AND socio_economic ILIKE '%" + setAside + "%'" : ''} ORDER BY CASE relationship_strength WHEN 'Strong' THEN 1 WHEN 'Active' THEN 2 WHEN 'Warm' THEN 3 WHEN 'New' THEN 4 ELSE 5 END, updated_at DESC LIMIT 20;`;
    break;
  default:
    query = `SELECT * FROM gda_teaming_partners ORDER BY CASE relationship_strength WHEN 'Strong' THEN 1 WHEN 'Active' THEN 2 WHEN 'Warm' THEN 3 ELSE 4 END, updated_at DESC LIMIT ${parseInt(body.limit) || 50};`;
    meta.action = 'list';
}
return [{ json: { query, meta } }];

const meta = $('Build Query').first().json.meta;
const rows = $input.all().map(i => i.json).filter(r => r.id !== undefined);
const resp = { status: 'ok', action: meta.action };
if (meta.action === 'upsert') resp.partner = rows[0] || null;
else if (meta.action === 'delete') resp.deleted = rows[0] || null;
else { resp.partners = rows; resp.count = rows.length; }
resp.timestamp = new Date().toISOString();
return [{ json: resp }];
